// Format YouTube GPT response for callback
const gptResponse = $input.first().json;
const prevData = $('Format Transcript').first().json;

if (prevData.error) {
  return {
    json: {
      callbackUrl: prevData.callbackUrl,
      callbackSecret: prevData.callbackSecret,
      importId: prevData.importId,
      error: prevData.error,
      rawContent: prevData.transcriptText || ''
    }
  };
}

let parsedRecipe;
try {
  const content = gptResponse.message?.content || gptResponse.text || JSON.stringify(gptResponse);
  parsedRecipe = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  return {
    json: {
      callbackUrl: prevData.callbackUrl,
      callbackSecret: prevData.callbackSecret,
      importId: prevData.importId,
      error: 'Failed to parse GPT response: ' + e.message,
      rawContent: prevData.transcriptText || ''
    }
  };
}

if (parsedRecipe.error) {
  return {
    json: {
      callbackUrl: prevData.callbackUrl,
      callbackSecret: prevData.callbackSecret,
      importId: prevData.importId,
      error: parsedRecipe.error,
      rawContent: prevData.transcriptText || ''
    }
  };
}

return {
  json: {
    callbackUrl: prevData.callbackUrl,
    callbackSecret: prevData.callbackSecret,
    importId: prevData.importId,
    recipe: parsedRecipe,
    rawContent: prevData.transcriptText || '',
    rawMetadata: { title: parsedRecipe.title, url: prevData.url, source: 'youtube-' + (prevData.sourceType || 'transcript') }
  }
};

// Try to extract JSON-LD Recipe structured data from HTML
const html = $input.first().json.data || $input.first().json.body || '';
const url = $('Validate URL').first().json.url;
const importId = $('Validate URL').first().json.importId;
const callbackUrl = $('Validate URL').first().json.callbackUrl;
const callbackSecret = $('Validate URL').first().json.callbackSecret;

if (!html || html.length < 100) {
  return {
    json: {
      hasJsonLd: false,
      rawText: '',
      importId,
      callbackUrl,
      callbackSecret,
      url,
      error: 'Failed to fetch page content'
    }
  };
}

const jsonLdRegex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
let match;
let recipe = null;

while ((match = jsonLdRegex.exec(html)) !== null) {
  try {
    let parsed = JSON.parse(match[1].trim());
    if (parsed['@graph']) {
      parsed = parsed['@graph'];
    }
    const items = Array.isArray(parsed) ? parsed : [parsed];
    for (const item of items) {
      if (item['@type'] === 'Recipe' || 
          (Array.isArray(item['@type']) && item['@type'].includes('Recipe'))) {
        recipe = item;
        break;
      }
    }
    if (recipe) break;
  } catch (e) {}
}

const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const htmlTitle = titleMatch ? titleMatch[1].trim() : '';

if (recipe) {
  // Parse JSON-LD ingredients with smarter extraction
  const ingredients = (recipe.recipeIngredient || []).map((ing) => {
    const text = typeof ing === 'string' ? ing.trim() : '';
    // Separate preparation notes after comma
    const prepMatch = text.match(/,\s*(.+)$/);
    const preparation = prepMatch ? prepMatch[1].trim() : null;
    const nameWithoutPrep = prepMatch ? text.replace(prepMatch[0], '').trim() : text;
    // Strip leading quantity+unit for canonicalName
    const canon = nameWithoutPrep
      .replace(/^[\d\/.\s]+(g|kg|ml|L|oz|lb|cups?|tbsp|tsp|fl\s*oz|pcs|pieces?)?\s*/i, '')
      .replace(/^of\s+/i, '')
      .trim();
    return {
      name: text,
      canonicalName: canon || text,
      preparation: preparation,
      quantity: null,
      unit: null,
      optional: false,
      ingredientGroup: null
    };
  });

  // Parse instruction sections, preserving group names
  const steps = [];
  const instructions = recipe.recipeInstructions || [];
  if (Array.isArray(instructions)) {
    for (const step of instructions) {
      if (typeof step === 'string') {
        steps.push(step);
      } else if (step.text) {
        steps.push(step.text);
      } else if (step.itemListElement) {
        for (const sub of step.itemListElement) {
          if (sub.text) steps.push(sub.text);
          else if (typeof sub === 'string') steps.push(sub);
        }
      }
    }
  } else if (typeof instructions === 'string') {
    steps.push(instructions);
  }

  function parseDuration(dur) {
    if (!dur) return null;
    const m = dur.match(/PT(?:(\d+)H)?(?:(\d+)M)?/);
    if (!m) return null;
    return (parseInt(m[1] || '0') * 60) + parseInt(m[2] || '0');
  }

  const parsedRecipe = {
    title: recipe.name || htmlTitle || 'Untitled Recipe',
    servings: recipe.recipeYield ? parseInt(String(recipe.recipeYield)) || null : null,
    prepTimeMinutes: parseDuration(recipe.prepTime),
    cookTimeMinutes: parseDuration(recipe.cookTime),
    totalTimeMinutes: parseDuration(recipe.totalTime),
    ingredients: ingredients,
    steps: steps,
    imageUrl: Array.isArray(recipe.image) ? recipe.image[0] : (recipe.image?.url || recipe.image || null)
  };

  return {
    json: {
      hasJsonLd: true,
      parsedRecipe,
      importId,
      callbackUrl,
      callbackSecret,
      url,
      rawText: html.substring(0, 5000)
    }
  };
}

const textContent = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 6000);

return {
  json: {
    hasJsonLd: false,
    rawText: textContent,
    htmlTitle,
    importId,
    callbackUrl,
    callbackSecret,
    url
  }
};

