    rawContent: prevData.rawText,
    rawMetadata: { title: parsedRecipe.title, url: prevData.url, source: 'gpt' }
  }
};

// Format JSON-LD result for callback
const data = $input.first().json;

return {
  json: {
    callbackUrl: data.callbackUrl,
    callbackSecret: data.callbackSecret,
    importId: data.importId,
    recipe: data.parsedRecipe,
    rawContent: data.rawText,
    rawMetadata: { title: data.parsedRecipe.title, url: data.url, source: 'json-ld' }
  }
